import anthropic
import json
from dataclasses import dataclass, field

client = anthropic.Anthropic()

@dataclass
class UserProfile:
    user_id: str
    facts: dict[str, str] = field(default_factory=dict)

# In production: persist to database
_profiles: dict[str, UserProfile] = {}

def get_profile(user_id: str) -> UserProfile:
    return _profiles.setdefault(user_id, UserProfile(user_id=user_id))

def extract_facts(conversation: list[dict]) -> dict:
    """Use the model to extract key facts from the conversation."""
    transcript = "\n".join(f"{m['role'].upper()}: {m['content']}" for m in conversation)
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=128,
        system="""Extract any personal facts stated by the user (name, job, preferences, constraints).
        Output JSON: {"facts": {"key": "value", ...}} — use null if no new facts found.""",
        messages=[{"role": "user", "content": transcript}],
    )
    try:
        data = json.loads(response.content[0].text)
        return data.get("facts") or {}
    except (json.JSONDecodeError, KeyError):
        return {}

def update_user_facts(user_id: str, conversation: list[dict]) -> None:
    """Extract facts from conversation and merge into user profile."""
    new_facts = extract_facts(conversation)
    profile = get_profile(user_id)
    profile.facts.update({k: v for k, v in new_facts.items() if v})  # skip null values

def facts_to_system_context(user_id: str) -> str:
    """Format user facts for injection into system prompt."""
    profile = get_profile(user_id)
    if not profile.facts:
        return ""
    lines = [f"  {k}: {v}" for k, v in profile.facts.items()]
    return "Known about this user:\n" + "\n".join(lines)

# Example usage
update_user_facts("user-42", [
    {"role": "user",      "content": "Hi, I'm Dr. Priya Patel, a cardiologist in Boston."},
    {"role": "assistant", "content": "Nice to meet you, Dr. Patel!"},
])
print(get_profile("user-42").facts)
# {'name': 'Dr. Priya Patel', 'job': 'cardiologist', 'location': 'Boston'}
